use actix_files::Files;
use actix_web::{web, App, HttpServer, Responder};
use std::path::Path;

async fn serve_file(path: web::Path<String>) -> impl Responder {
    let filename = path.into_inner();
    let file_path = Path::new("uploads").join(filename);
    
    if !file_path.exists() {
        return actix_web::HttpResponse::NotFound().body("File not found");
    }

    Files::new("/", "uploads")
        .index_file("index.html")
        .serve_file(file_path)
        .await
        .unwrap_or_else(|_| actix_web::HttpResponse::InternalServerError())
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/uploads/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}